import React, { useEffect, useState } from 'react';
import API from '../api/axios';
import { Link } from 'react-router-dom';

function HomePage() {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  
  // Siguraduhing tama ang port ng backend mo (halimbawa 5000)
  const IMG_URL = 'http://localhost:5000/uploads/'; 

  useEffect(() => {
    API.get('/posts')
      .then(res => {
        setPosts(res.data);
        setLoading(false);
      })
      .catch(err => {
        console.error("Error fetching posts:", err);
        setLoading(false);
      });
  }, []);

  return (
    <main>
      {/* SECTION 1: HERO (Static Content) */}
      <section className="hero">
        <h1>The Purr</h1>
        <p>
          It isn't merely a sound—it’s a low-frequency engine of contentment, 
          a biological hum that suggests the cat is vibrating at a different 
          frequency than the rest of the world.
        </p>
        <br />
        <img src="/photos/c1.jpg" width="350" height="350" alt="Cead" />
      </section>

      {/* SECTION 2: DYNAMIC POSTS (From Database) */}
      <h2 style={{ textAlign: 'center', marginTop: '40px' }}>Latest Stories</h2>
      <section className="preview-grid">
        {loading ? (
          <p style={{ textAlign: 'center' }}>Loading amazing stories...</p>
        ) : (
          posts.map((post) => (
            <div className="card one" key={post._id}>
              <Link to={`/posts/${post._id}`} style={{ textDecoration: 'none', color: 'inherit' }}>
                <h3>{post.title}</h3>
                <p>{post.body.substring(0, 100)}...</p>
                <br />
                
                {/* Dito lalabas yung in-upload mong image */}
                {post.image ? (
                  <img 
                    src={`${IMG_URL}${post.image}`} 
                    width="250" 
                    height="250" 
                    alt={post.title} 
                    style={{ objectFit: 'cover' }}
                  />
                ) : (
                  /* Fallback image kung walang inupload */
                  <img src="/photos/c2.jpg" width="250" height="250" alt="Default" />
                )}
              </Link>
            </div>
          ))
        )}
      </section>

      {/* SECTION 3: FOOTER */}
      <footer>
        <p>&copy; MiIlao. All rights reserved. | Contact: MiIlao@gmail.com</p>
      </footer>
    </main>
  );
}

export default HomePage;
